    private void btnInstanciarGameShopActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnInstanciarGameShopActionPerformed
        objGame = new GameShop(
                Integer.parseInt(txtCodigo.getText()),
                txtNome.getText(),
                rdbFrequente.isSelected(),
                100);
        
        objGame.setIdade(Integer.parseInt(txtIdade.getText()));
        txtSaldoDeHoras.setText(String.valueOf(objGame.getSaldo()));
        
        // Desabilita Campos
        txtCodigo.setEnabled(false);
        txtNome.setEnabled(false);
        txtIdade.setEnabled(false);
        
        rdbFrequente.setEnabled(false);
        rdbEsporadico.setEnabled(false);
        
        btnInstanciarGameShop.setEnabled(false);
        
        // Habilitar Operações
        btnJogar.setEnabled(true);
        btnComprar.setEnabled(true);
        btnBrinde.setEnabled(true);
               
    }//GEN-LAST:event_btnInstanciarGameShopActionPerformed

