    private void btnJogarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnJogarActionPerformed
         int horas = Integer.parseInt(txtQtdeHoras.getText());

    boolean retorno = objGame.jogarHoras(horas);

    if(retorno == false){
        JOptionPane.showMessageDialog(null,
                                      "Saldo de horas insuficiente");
    }

    txtSaldoDeHoras.setText(String.valueOf(objGame.getSaldo()));
    }//GEN-LAST:event_btnJogarActionPerformed

    private void btnComprarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnComprarActionPerformed
        int horas = Integer.parseInt(txtQtdeHoras.getText());

    objGame.comprarHoras(horas);

    txtSaldoDeHoras.setText(String.valueOf(objGame.getSaldo()));
    }//GEN-LAST:event_btnComprarActionPerformed

    private void btnBrindeActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnBrindeActionPerformed
         objGame.brinde();

    txtSaldoDeHoras.setText(String.valueOf(objGame.getSaldo()));
    }//GEN-LAST:event_btnBrindeActionPerformed

